const { app } = require('@azure/functions');
const { exec } = require('child_process');
const path = require('path');
const fs = require('fs').promises;
const crypto = require('crypto');

const ALLOWED_INPUT_EXTENSIONS = ['.doc', '.docx', '.odt', '.rtf', '.txt', '.xls', '.xlsx', '.ods', '.ppt', '.pptx', '.odp'];
const ALLOWED_OUTPUT_FORMATS = ['pdf', 'docx', 'odt', 'html', 'txt', 'xlsx', 'ods', 'pptx', 'odp'];
const TEMP_DIR = process.env.TEMP || '/tmp';
const LIBREOFFICE_PATH = process.env.LIBREOFFICE_PATH || '/usr/bin/libreoffice';
const MAX_FILE_SIZE = 50 * 1024 * 1024;
const CONVERSION_TIMEOUT = 120000;

function sanitizeFilename(filename) {
    const basename = path.basename(filename);
    return basename.replace(/[^a-zA-Z0-9._-]/g, '_');
}

function validateInputFile(filename) {
    const ext = path.extname(filename).toLowerCase();
    if (!ALLOWED_INPUT_EXTENSIONS.includes(ext)) {
        throw new Error(`Invalid input file extension. Allowed: ${ALLOWED_INPUT_EXTENSIONS.join(', ')}`);
    }
    return true;
}

function validateOutputFormat(format) {
    const normalizedFormat = format.toLowerCase();
    if (!ALLOWED_OUTPUT_FORMATS.includes(normalizedFormat)) {
        throw new Error(`Invalid output format. Allowed: ${ALLOWED_OUTPUT_FORMATS.join(', ')}`);
    }
    return normalizedFormat;
}

async function checkFileSize(filePath) {
    try {
        const stats = await fs.stat(filePath);
        if (stats.size > MAX_FILE_SIZE) {
            throw new Error(`File size exceeds maximum allowed size of ${MAX_FILE_SIZE / 1024 / 1024}MB`);
        }
        return true;
    } catch (error) {
        throw new Error(`Unable to check file size: ${error.message}`);
    }
}

function executeLibreOffice(inputPath, outputDir, outputFormat) {
    return new Promise((resolve, reject) => {
        const sanitizedInputPath = inputPath.replace(/'/g, "'\\''");
        const sanitizedOutputDir = outputDir.replace(/'/g, "'\\''");
        const sanitizedFormat = outputFormat.replace(/[^a-z0-9]/g, '');
        
        const command = `'${LIBREOFFICE_PATH}' --headless --convert-to ${sanitizedFormat} --outdir '${sanitizedOutputDir}' '${sanitizedInputPath}'`;
        
        const timeout = setTimeout(() => {
            if (process) {
                process.kill();
            }
            reject(new Error('Conversion timeout exceeded'));
        }, CONVERSION_TIMEOUT);

        exec(command, { 
            timeout: CONVERSION_TIMEOUT,
            maxBuffer: 10 * 1024 * 1024,
            shell: '/bin/bash'
        }, (error, stdout, stderr) => {
            clearTimeout(timeout);
            
            if (error) {
                reject(new Error(`Conversion failed: ${error.message}`));
                return;
            }
            
            resolve({ stdout, stderr });
        });
    });
}

async function cleanupFiles(...filePaths) {
    for (const filePath of filePaths) {
        try {
            await fs.unlink(filePath);
        } catch (error) {
            console.error(`Failed to cleanup file ${filePath}:`, error.message);
        }
    }
}

app.http('convertDocument', {
    methods: ['POST'],
    authLevel: 'function',
    handler: async (request, context) => {
        let tempInputPath = null;
        let tempOutputPath = null;
        let tempWorkDir = null;

        try {
            const body = await request.json();
            
            if (!body || !body.filename || !body.outputFormat) {
                return {
                    status: 400,
                    jsonBody: {
                        error: 'Missing required fields: filename and outputFormat'
                    }
                };
            }

            const { filename, outputFormat, fileContent } = body;

            if (!fileContent) {
                return {
                    status: 400,
                    jsonBody: {
                        error: 'Missing fileContent (base64 encoded file data)'
                    }
                };
            }

            validateInputFile(filename);
            const validatedFormat = validateOutputFormat(outputFormat);
            const sanitizedFilename = sanitizeFilename(filename);

            const uniqueId = crypto.randomBytes(16).toString('hex');
            tempWorkDir = path.join(TEMP_DIR, `conversion_${uniqueId}`);
            await fs.mkdir(tempWorkDir, { recursive: true, mode: 0o700 });

            tempInputPath = path.join(tempWorkDir, sanitizedFilename);
            
            const fileBuffer = Buffer.from(fileContent, 'base64');
            await fs.writeFile(tempInputPath, fileBuffer, { mode: 0o600 });

            await checkFileSize(tempInputPath);

            await executeLibreOffice(tempInputPath, tempWorkDir, validatedFormat);

            const inputBasename = path.parse(sanitizedFilename).name;
            const outputFilename = `${inputBasename}.${validatedFormat}`;
            tempOutputPath = path.join(tempWorkDir, outputFilename);

            let outputExists = false;
            try {
                await fs.access(tempOutputPath);
                outputExists = true;
            } catch (error) {
                outputExists = false;
            }

            if (!outputExists) {
                return {
                    status: 500,
                    jsonBody: {
                        error: 'Conversion completed but output file not found'
                    }
                };
            }

            const convertedFile = await fs.readFile(tempOutputPath);
            const base64Output = convertedFile.toString('base64');

            await cleanupFiles(tempInputPath, tempOutputPath);
            try {
                await fs.rmdir(tempWorkDir);
            } catch (error) {
                console.error('Failed to remove temp directory:', error.message);
            }

            return {
                status: 200,
                jsonBody: {
                    success: true,
                    outputFilename: outputFilename,
                    outputFormat: validatedFormat,
                    fileContent: base64Output
                }
            };

        } catch (error) {
            context.error('Conversion error:', error);

            if (tempInputPath || tempOutputPath || tempWorkDir) {
                await cleanupFiles(tempInputPath, tempOutputPath);
                if (tempWorkDir) {
                    try {
                        const files = await fs.readdir(tempWorkDir);
                        for (const file of files) {
                            await fs.unlink(path.join(tempWorkDir, file));
                        }
                        await fs.rmdir(tempWorkDir);
                    } catch (cleanupError) {
                        context.error('Cleanup error:', cleanupError);
                    }
                }
            }

            return {
                status: 500,
                jsonBody: {
                    error: error.message || 'Document conversion failed'
                }
            };
        }
    }
});